function clearDeferredObjectKeysPlaceholderLocal(
  localName: string,
  context: FunctionLoweringContext,
): void {
  context.functionRuntime.deferredObjectKeysPlaceholderLocals.delete(localName);
}

function getDeferredObjectKeysPlaceholderLocalName(
  expression: ts.Expression,
  context: FunctionLoweringContext,
): string | undefined {
  if (ts.isParenthesizedExpression(expression)) {
    return getDeferredObjectKeysPlaceholderLocalName(expression.expression, context);
  }
  if (
    ts.isAsExpression(expression) &&
    (
      isRepresentationSafeHeapCast(context.checker, expression) ||
      isHeapToBagGeneralizationCast(context.checker, expression)
    )
  ) {
    return getDeferredObjectKeysPlaceholderLocalName(expression.expression, context);
  }
  if (ts.isIdentifier(expression)) {
    const bound = lookupSymbol(context, expression.text);
    if (
      bound?.type === 'heap_ref' &&
      context.functionRuntime.deferredObjectKeysPlaceholderLocals.has(bound.emittedName)
    ) {
      return bound.emittedName;
    }
  }
  return undefined;
}

function isDeferredObjectKeysPlaceholderExpression(
  expression: ts.Expression,
  context: FunctionLoweringContext,
): boolean {
  if (ts.isParenthesizedExpression(expression)) {
    return isDeferredObjectKeysPlaceholderExpression(expression.expression, context);
  }
  if (
    ts.isAsExpression(expression) &&
    (
      isRepresentationSafeHeapCast(context.checker, expression) ||
      isHeapToBagGeneralizationCast(context.checker, expression)
    )
  ) {
    return isDeferredObjectKeysPlaceholderExpression(expression.expression, context);
  }
  return getDeferredObjectKeysPlaceholderLocalName(expression, context) !== undefined;
}

function isCanonicalArrayIndexPropertyKey(propertyKey: string): boolean {
  if (!/^(0|[1-9]\d*)$/.test(propertyKey)) {
    return false;
  }
  const numericKey = Number(propertyKey);
  return Number.isInteger(numericKey) &&
    numericKey >= 0 &&
    numericKey <= 4_294_967_294 &&
    String(numericKey) === propertyKey;
}

function isExplicitBagBoundaryExpression(
  expression: ts.Expression,
  checker: ts.TypeChecker,
): boolean {
  if (ts.isParenthesizedExpression(expression)) {
    return isExplicitBagBoundaryExpression(expression.expression, checker);
  }

  return ts.isAsExpression(expression) && isHeapToBagGeneralizationCast(checker, expression);
}

function lowerSpecializedObjectMembership(
  objectName: string,
  representation: CompilerRuntimeSpecializedObjectRepresentationRefIR,
  propertyKey: string,
  context: FunctionLoweringContext,
): CompilerExpressionIR {
  const fieldIndex = getSpecializedObjectFieldIndex(context.runtime, representation, propertyKey);
  if (fieldIndex === undefined) {
    const prototypeMembership = getOrdinaryObjectPrototypeMembershipForSpecializedRepresentation(
      context.runtime,
      representation,
    );
    return {
      kind: 'boolean_literal',
      value: prototypeMembership.inheritedPropertyKeys.includes(propertyKey),
    };
  }

  const resultName = createLocalName(`${propertyKey}_has`, context.nextLocalId);
  context.nextLocalId += 1;
  context.locals.push({ name: resultName, type: 'i32' });
  const operation: CompilerRuntimeHasSpecializedObjectOwnPropertyIR = {
    kind: 'has_specialized_object_own_property',
    objectName,
    resultName,
    representation,
    fieldIndex,
  };
  context.functionRuntime.operations.push(operation);
  return {
    kind: 'local_get',
    name: resultName,
    type: 'i32',
  };
}

