function lowerOrdinaryObjectPropertyReadAsValueType(
  objectName: string,
  representation: CompilerRuntimeObjectRepresentationRef,
  propertyKey: string,
  resultType: CompilerValueType,
  diagnosticNode: ts.Node,
  context: FunctionLoweringContext,
): CompilerExpressionIR {
  if (representation.kind === 'fallback_object_representation') {
    return lowerFallbackObjectPropertyReadAsValueType(
      objectName,
      representation,
      propertyKey,
      resultType,
      context,
    );
  }
  if (representation.kind === 'dynamic_object_representation') {
    const keyStatements: CompilerStatementIR[] = [];
    const propertyKeyName = createOwnedStringLiteralLocal(
      propertyKey,
      context,
      keyStatements,
      `${propertyKey}_key`,
    );
    context.expressionPreludeStatements.push(...keyStatements);
    return lowerDynamicObjectPropertyReadAsValueType(
      objectName,
      representation,
      propertyKeyName,
      resultType,
      context,
    );
  }
  return lowerSpecializedObjectPropertyReadAsValueType(
    objectName,
    representation,
    propertyKey,
    resultType,
    diagnosticNode,
    context,
  );
}

function lowerOrdinaryObjectMembershipByStaticPropertyKey(
  objectName: string,
  representation: CompilerRuntimeObjectRepresentationRef,
  propertyKey: string,
  context: FunctionLoweringContext,
): CompilerExpressionIR {
  if (representation.kind === 'fallback_object_representation') {
    return lowerFallbackObjectMembership(objectName, representation, propertyKey, context);
  }
  if (representation.kind === 'dynamic_object_representation') {
    const keyStatements: CompilerStatementIR[] = [];
    const propertyKeyName = createOwnedStringLiteralLocal(
      propertyKey,
      context,
      keyStatements,
      `${propertyKey}_key`,
    );
    context.expressionPreludeStatements.push(...keyStatements);
    return lowerDynamicObjectMembership(objectName, representation, propertyKeyName, context);
  }
  return lowerSpecializedObjectMembership(objectName, representation, propertyKey, context);
}

function lowerSpecializedObjectPropertyReadAsValueType(
  objectName: string,
  representation: CompilerRuntimeSpecializedObjectRepresentationRefIR,
  propertyKey: string,
  resultType: CompilerValueType,
  diagnosticNode: ts.Node,
  context: FunctionLoweringContext,
): CompilerExpressionIR {
  const fieldLayout = getSpecializedObjectFieldValueLayout(
    context.runtime,
    representation,
    propertyKey,
  );
  if (!fieldLayout) {
    throw new CompilerUnsupportedError(
      'Only known fixed-layout object properties can be read in compiler subset.',
      diagnosticNode,
    );
  }

  const readRawField = (): CompilerExpressionIR => {
    const rawValueType = fieldLayout.valueType;
    if (rawValueType === 'class_constructor_ref') {
      throw new CompilerUnsupportedError(
        'Class-constructor ordinary-object Object.values flows are not supported in compiler subset.',
        diagnosticNode,
      );
    }
    const resultName = createLocalName(propertyKey, context.nextLocalId);
    context.nextLocalId += 1;
    context.locals.push({ name: resultName, type: rawValueType });
    context.functionRuntime.operations.push({
      kind: 'get_specialized_object_field',
      objectName,
      resultName,
      representation,
      fieldIndex: fieldLayout.fieldIndex,
    });
    return {
      kind: 'local_get',
      name: resultName,
      type: rawValueType,
    };
  };

  if (resultType === 'tagged_ref') {
    ensureTaggedValueRepresentation(context.runtime);
    switch (fieldLayout.valueType) {
      case 'f64':
        return {
          kind: 'tag_number',
          value: readRawField(),
          type: 'tagged_ref',
        };
      case 'i32':
        return {
          kind: 'tag_boolean',
          value: readRawField(),
          type: 'tagged_ref',
        };
      case 'tagged_ref':
        return readRawField();
      case 'heap_ref':
      case 'owned_array_ref':
      case 'owned_heap_array_ref':
      case 'owned_number_array_ref':
      case 'owned_boolean_array_ref':
      case 'owned_tagged_array_ref':
      case 'class_constructor_ref':
      case 'closure_ref':
        return {
          kind: 'tag_heap_object',
          value: readRawField(),
          type: 'tagged_ref',
        };
      default:
        throw new CompilerUnsupportedError(
          'Only taggable specialized object property values are supported in compiler subset.',
          diagnosticNode,
        );
    }
  }

  if (fieldLayout.valueType !== resultType) {
    throw new CompilerUnsupportedError(
      'Only homogeneous ordinary-object Object.values flows are supported in compiler subset.',
      diagnosticNode,
    );
  }

  return readRawField();
}

function tryLowerOrdinaryObjectValuesExpression(
  expression: ts.Expression,
  expectedResultType:
    | 'owned_array_ref'
    | 'owned_number_array_ref'
    | 'owned_boolean_array_ref'
    | 'owned_tagged_array_ref',
  context: FunctionLoweringContext,
): CompilerExpressionIR | undefined {
  if (!ts.isCallExpression(expression) || !isObjectValuesCall(expression)) {
    return undefined;
  }
  if (expression.arguments.length !== 1) {
    throw new CompilerUnsupportedError(
      'Object.values calls must receive exactly one argument.',
      expression,
    );
  }

  const receiver = expression.arguments[0]!;
  let objectName = isExplicitBagBoundaryExpression(receiver, context.checker)
    ? undefined
    : getHeapObjectValueNameFromExpression(receiver, context);
  let sourceRepresentation = getHeapObjectRepresentationFromExpression(receiver, context);
  let boundaryRepresentation = sourceRepresentation?.kind === 'fallback_object_representation' &&
      !isExplicitBagBoundaryExpression(receiver, context.checker)
    ? sourceRepresentation
    : getOrdinaryObjectInBoundaryRepresentationFromExpression(receiver, context);
  if (!boundaryRepresentation) {
    throw createUnsupportedObjectValuesReceiverError(receiver, context.checker);
  }
  if (!objectName) {
    const materialized = isExplicitBagBoundaryExpression(receiver, context.checker)
      ? forceMaterializeHeapExpressionToLocal(receiver, context, 'object_values_object')
      : materializeHeapExpressionToLocal(receiver, context, 'object_values_object');
    objectName = materialized.name;
    sourceRepresentation = materialized.representation;
  }
  if (
    boundaryRepresentation.kind === 'fallback_object_representation' &&
    sourceRepresentation?.kind === 'specialized_object_representation'
  ) {
    recordFallbackObjectGeneralization(
      objectName,
      sourceRepresentation,
      boundaryRepresentation,
      context,
    );
  }
  if (boundaryRepresentation.kind === 'dynamic_object_representation') {
    return lowerDynamicObjectValues(
      objectName,
      boundaryRepresentation,
      expectedResultType,
      context,
    );
  }
  const propertyKeys = getProvenSpecializedObjectOwnPropertyKeyOrderFromExpression(
    receiver,
    context,
  );
  if (!propertyKeys) {
    throw new CompilerUnsupportedError(
      boundaryRepresentation.kind === 'fallback_object_representation'
        ? 'Only fallback ordinary-object Object.values receivers with provable own-key order are supported in compiler subset.'
        : 'Only specialized ordinary-object Object.values receivers with provable own-key order are supported in compiler subset.',
      receiver,
    );
  }

  const elementType = expectedResultType === 'owned_array_ref'
    ? 'owned_string_ref'
    : expectedResultType === 'owned_number_array_ref'
    ? 'f64'
    : expectedResultType === 'owned_boolean_array_ref'
    ? 'i32'
    : 'tagged_ref';

  if (expectedResultType === 'owned_tagged_array_ref') {
    ensureTaggedValueRepresentation(context.runtime);
    const expressionType = context.checker.getTypeAtLocation(expression);
    const kinds = getSupportedOwnedTaggedArrayKinds(context.checker, expressionType);
    if (kinds?.includesString) {
      ensureStringRepresentation(context.runtime);
    }
  }

  const elements = propertyKeys.map((propertyKey) =>
    lowerOrdinaryObjectPropertyReadAsValueType(
      objectName,
      boundaryRepresentation,
      propertyKey,
      elementType,
      expression,
      context,
    )
  );

  switch (expectedResultType) {
    case 'owned_array_ref':
      return {
        kind: 'owned_string_array_literal',
        elements,
        type: 'owned_array_ref',
      };
    case 'owned_number_array_ref':
      return {
        kind: 'owned_number_array_literal',
        elements,
        type: 'owned_number_array_ref',
      };
    case 'owned_boolean_array_ref':
      return {
        kind: 'owned_boolean_array_literal',
        elements,
        type: 'owned_boolean_array_ref',
      };
    case 'owned_tagged_array_ref':
      return {
        kind: 'owned_tagged_array_literal',
        elements,
        type: 'owned_tagged_array_ref',
      };
  }
}

function tryLowerOrdinaryObjectEntriesExpression(
  expression: ts.Expression,
  context: FunctionLoweringContext,
): CompilerExpressionIR | undefined {
  if (!ts.isCallExpression(expression) || !isObjectEntriesCall(expression)) {
    return undefined;
  }
  if (expression.arguments.length !== 1) {
    throw new CompilerUnsupportedError(
      'Object.entries calls must receive exactly one argument.',
      expression,
    );
  }

  const receiver = expression.arguments[0]!;
  let objectName = isExplicitBagBoundaryExpression(receiver, context.checker)
    ? undefined
    : getHeapObjectValueNameFromExpression(receiver, context);
  let sourceRepresentation = getHeapObjectRepresentationFromExpression(receiver, context);
  const boundaryRepresentation = sourceRepresentation?.kind === 'fallback_object_representation' &&
      !isExplicitBagBoundaryExpression(receiver, context.checker)
    ? sourceRepresentation
    : getOrdinaryObjectInBoundaryRepresentationFromExpression(receiver, context);
  if (!boundaryRepresentation) {
    throw createUnsupportedObjectEntriesReceiverError(receiver, context.checker);
  }
  if (!objectName) {
    const materialized = isExplicitBagBoundaryExpression(receiver, context.checker)
      ? forceMaterializeHeapExpressionToLocal(receiver, context, 'object_entries_object')
      : materializeHeapExpressionToLocal(receiver, context, 'object_entries_object');
    objectName = materialized.name;
    sourceRepresentation = materialized.representation;
  }
  if (
    boundaryRepresentation.kind === 'fallback_object_representation' &&
    sourceRepresentation?.kind === 'specialized_object_representation'
  ) {
    recordFallbackObjectGeneralization(
      objectName,
      sourceRepresentation,
      boundaryRepresentation,
      context,
    );
  }
  if (boundaryRepresentation.kind === 'dynamic_object_representation') {
    return lowerDynamicObjectEntries(
      objectName,
      boundaryRepresentation,
      dynamicOrdinaryObjectEntriesUseOwnedStringPairs(receiver, context)
        ? 'owned_string_ref'
        : 'tagged_ref',
      context,
    );
  }
  const propertyKeys = getProvenSpecializedObjectOwnPropertyKeyOrderFromExpression(
    receiver,
    context,
  );
  if (!propertyKeys) {
    throw new CompilerUnsupportedError(
      boundaryRepresentation.kind === 'fallback_object_representation'
        ? 'Only fallback ordinary-object Object.entries receivers with provable own-key order are supported in compiler subset.'
        : 'Only specialized ordinary-object Object.entries receivers with provable own-key order are supported in compiler subset.',
      receiver,
    );
  }

  ensureTaggedValueRepresentation(context.runtime);
  ensureStringRepresentation(context.runtime);

  const useOwnedStringPairs = ordinaryObjectEntriesUseOwnedStringPairs(
    receiver,
    propertyKeys,
    context,
  );

  return {
    kind: 'owned_heap_array_literal',
    elements: propertyKeys.map((propertyKey) => {
      const keyLiteral: CompilerExpressionIR = {
        kind: 'owned_string_literal',
        literalId: getOrCreateStringLiteralId(propertyKey, context.runtime),
        type: 'owned_string_ref',
      };
      if (useOwnedStringPairs) {
        return {
          kind: 'owned_string_array_literal',
          elements: [
            keyLiteral,
            lowerOrdinaryObjectPropertyReadAsValueType(
              objectName,
              boundaryRepresentation,
              propertyKey,
              'owned_string_ref',
              expression,
              context,
            ),
          ],
          type: 'owned_array_ref',
        } satisfies CompilerExpressionIR;
      }
      return {
        kind: 'owned_tagged_array_literal',
        elements: [
          {
            kind: 'tag_string',
            value: keyLiteral,
            type: 'tagged_ref',
          },
          lowerOrdinaryObjectPropertyReadAsValueType(
            objectName,
            boundaryRepresentation,
            propertyKey,
            'tagged_ref',
            expression,
            context,
          ),
        ],
        type: 'owned_tagged_array_ref',
      } satisfies CompilerExpressionIR;
    }),
    type: 'owned_heap_array_ref',
  };
}

function lowerSpecializedObjectKeys(
  objectName: string,
  receiver: ts.Expression,
  representation: CompilerRuntimeSpecializedObjectRepresentationRefIR,
  context: FunctionLoweringContext,
): CompilerExpressionIR {
  const propertyKeys = context.functionRuntime.provenSpecializedObjectKeyOrderByLocal.get(
    objectName,
  );
  if (!propertyKeys) {
    throw new CompilerUnsupportedError(
      'Only specialized ordinary-object Object.keys receivers with provable own-key order are supported in compiler subset.',
      receiver,
    );
  }
  const resultName = createLocalName('object_keys', context.nextLocalId);
  context.nextLocalId += 1;
  context.locals.push({ name: resultName, type: 'heap_ref' });
  const operation: CompilerRuntimeListSpecializedObjectKeysIR = {
    kind: 'list_specialized_object_keys',
    objectName,
    resultName,
    representation,
    propertyKeys,
  };
  context.functionRuntime.operations.push(operation);
  return {
    kind: 'local_get',
    name: resultName,
    type: 'heap_ref',
  };
}

